function [dPhidt,tau_q,KE,P,M] = SMS_dynamics_PID(t, state)

%including parameters
param;
Phi = state(1:9);
dPhi = state(10:18);

q = state(7:9);
q_dot = state(16:18);


%% For symbolic testing %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
t1 = Phi(1); % x
t2 = Phi(2); % y 
t3 = Phi(3); % z
t4 = Phi(4); % roll
t5 = Phi(5); % pitch
t6 = Phi(6); % yaw
t7 = Phi(7); % q1
t8 = Phi(8); % q2
t9 = Phi(9); % q3


t1dot = dPhi(1);
t2dot = dPhi(2);
t3dot = dPhi(3);
t4dot = dPhi(4);
t5dot = dPhi(5);
t6dot = dPhi(6);
t7dot = dPhi(7);
t8dot = dPhi(8);
t9dot = dPhi(9);
%%%%%%%%%%%%%%%%% Inertia parameters %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
I_bx = 1/12*m_b*(wb^2+hb^2);
I_by = 1/12*m_b*(lb^2+hb^2);
I_bz = 1/12*m_b*(lb^2+wb^2);

B_I_b = diag([I_bx, I_by, I_bz]);  % Base inertia (kg-m^2)

I_1x = 1/12*m_1*(w1^2+h1^2);
I_1y = 1/12*m_1*(l_1^2+h1^2);
I_1z = 1/12*m_1*(l_1^2+w1^2);

L1_I_1 = diag([I_1x, I_1y, I_1z]);  % Link1 inertia (kg-m^2)

I_2x = 1/12*m_2*(w2^2+h2^2);
I_2y = 1/12*m_2*(l_2^2+h2^2);
I_2z = 1/12*m_2*(l_2^2+w2^2);

L2_I_2 = diag([I_2x, I_2y, I_2z]);  % Link2 inertia (kg-m^2)

I_3x = 1/12*m_3*(w3^2+h3^2);
I_3y = 1/12*m_3*(l_3^2+h3^2);
I_3z = 1/12*m_3*(l_3^2+w3^2);

L3_I_3 = diag([I_3x, I_3y, I_3z]);  % Link1 inertia (kg-m^2)
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
%%%%%%%%%% Frame Tranformation matrices %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% Quaternion for rotation about z axis
Q = @(q) [0*sin(q/2); 0*sin(q/2); 1*sin(q/2);cos(q/2)];
% Transformation matrices
R_from_Q = @(Q) [1 - 2*(Q(2)^2 + Q(3)^2), 2*(Q(1)*Q(2) - Q(3)*Q(4)), 2*(Q(1)*Q(3) + Q(2)*Q(4));
    2*(Q(1)*Q(2) + Q(3)*Q(4)), 1 - 2*(Q(1)^2 + Q(3)^2), 2*(Q(2)*Q(3) - Q(1)*Q(4));
    2*(Q(1)*Q(3) - Q(2)*Q(4)), 2*(Q(2)*Q(3) + Q(1)*Q(4)), 1 - 2*(Q(1)^2 + Q(2)^2)];

r_X = @(r) [0 -r(3) r(2); r(3) 0 -r(1); -r(2) r(1) 0];

% Quaternion transformation from base to inertial frame (since only yaw motion is there thus only include state 6)
QNB = Q(state(6));
R_NB = R_from_Q(QNB);
% Trasformation from link 1 to base
QB1 = Q(q(1));
R_B1 = R_from_Q(QB1);
% Trasformation from link 2 to link 1
QB2 = Q(q(2));
R_12 = R_from_Q(QB2);
% Trasformation from link 2 to base
R_B2 = R_B1 * R_12;
% Trasformation from link 3 to link 2
QB3 = Q(q(3));
R_23 = R_from_Q(QB3);
% Trasformation from link 3 to base
R_B3 = R_B2 * R_23;


% Transformation from link 1 to inertial frame
R_N1 = R_NB * R_B1;
% Transformation from link 2 to inertial frame
R_N2 = R_NB * R_B2;
% Transformation from link 3 to inertial frame
R_N3 = R_NB * R_B3;
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
%% Transform satellite base inertia in the inertial frame
N_I_b = R_NB * B_I_b * R_NB';
%% Transform the link-1 inertia in to inertial frame
N_I_1 = R_N1 * L1_I_1 * R_N1';
%% Transform the link-2 inertia in to inertial frame
N_I_2 = R_N2 * L2_I_2 * R_N2';
%% Transform the link-3 inertia in to inertial frame
N_I_3 = R_N3 * L3_I_3 * R_N3';

% Position vector of satellite base centroid with respect to inertial frame 
N_r_b = state(1:3);

% Calculation of B_m_b (vector of satellite base CM pointing to the robotic
% arm mounting point)
B_L_b = [lb/2; 0; 0]; % B_M_b in body frame
N_L_b = R_NB * B_L_b;  % N_M_b in inertial frame


% position vector of centroid of Link-1 in the inertial frame
N_r_1 = N_r_b + N_L_b + 0.5 * R_N1 * L_l_1;


% position vector of centroid of Link-2 in the inertial frame
N_r_2 = N_r_b + N_L_b + R_N1 * L_l_1 + 0.5 * R_N2 * L_l_2;
 

% position vector of centroid of Link-2 in the inertial frame
