)*t5dot^2)/2 + (I_3x*t4dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - (I_3x*t5dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - (I_3y*t4dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 + (I_3y*t5dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - I_2x*cos(2*t6 + 2*t7 + 2*t8)*t4dot*t5dot + I_2y*cos(2*t6 + 2*t7 + 2*t8)*t4dot*t5dot - I_3x*cos(2*t6 + 2*t7 + 2*t8 + 2*t9)*t4dot*t5dot + I_3y*cos(2*t6 + 2*t7 + 2*t8 + 2*t9)*t4dot*t5dot + (l_1*l_2*m_2*sin(t8)*t6dot^2)/2 + (l_1*l_2*m_2*sin(t8)*t7dot^2)/2 + l_1*l_2*m_3*sin(t8)*t6dot^2 + l_1*l_2*m_3*sin(t8)*t7dot^2 - (l_2*l_3*m_3*sin(t9)*t9dot^2)/2 + (l_3*lb*m_3*sin(t7 + t8 + t9)*t6dot^2)/4 + (l_1*l_3*m_3*sin(t8 + t9)*t6dot^2)/2 + (l_1*l_3*m_3*sin(t8 + t9)*t7dot^2)/2 + (l_2*lb*m_2*sin(t7 + t8)*t6dot^2)/4 + (l_2*lb*m_3*sin(t7 + t8)*t6dot^2)/2 + l_1*l_3*m_3*sin(t8 + t9)*t6dot*t7dot + l_1*l_2*m_2*sin(t8)*t6dot*t7dot + 2*l_1*l_2*m_3*sin(t8)*t6dot*t7dot - l_2*l_3*m_3*sin(t9)*t6dot*t9dot - l_2*l_3*m_3*sin(t9)*t7dot*t9dot - l_2*l_3*m_3*sin(t9)*t8dot*t9dot;
