                                                                                                                                                                                                                                                                                                                                                                                                                                                 (I_3x*t4dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - (I_3x*t5dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - (I_3y*t4dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 + (I_3y*t5dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - I_3x*cos(2*t6 + 2*t7 + 2*t8 + 2*t9)*t4dot*t5dot + I_3y*cos(2*t6 + 2*t7 + 2*t8 + 2*t9)*t4dot*t5dot + (l_2*l_3*m_3*sin(t9)*t6dot^2)/2 + (l_2*l_3*m_3*sin(t9)*t7dot^2)/2 + (l_2*l_3*m_3*sin(t9)*t8dot^2)/2 + (l_3*lb*m_3*sin(t7 + t8 + t9)*t6dot^2)/4 + (l_1*l_3*m_3*sin(t8 + t9)*t6dot^2)/2 + (l_1*l_3*m_3*sin(t8 + t9)*t7dot^2)/2 + l_1*l_3*m_3*sin(t8 + t9)*t6dot*t7dot + l_2*l_3*m_3*sin(t9)*t6dot*t7dot + l_2*l_3*m_3*sin(t9)*t6dot*t8dot + l_2*l_3*m_3*sin(t9)*t7dot*t8dot];
 








%% define desired joint angles and rates
q_des = [-0.523599;0;0];
q_des_dot =[0; 0; 0];

%% PD Control joint torque
tau_q = K_p * (q_des - q) + K_d *(q_des_dot - q_dot);

tau =[0; 0; 0; 0; 0; 0; tau_q];

% Angular velocity of satellite body
omega_b = dPhi(4:6);
% Angular velocity of link-1
omega_1 = omega_b + R_N1 * k * q_dot(1);
omega_2 = omega_b + R_N1 * k * q_dot(1) + R_N2 * k * q_dot(2);
omega_3 = omega_b + R_N1 * k * q_dot(1) + R_N2 * k * q_dot(2) + R_N3 * k * q_dot(3);

vel_b = dPhi(1:3);

vel_1 = vel_b + cross(omega_b,N_L_b) + 0.5 * cross(omega_1,(R_N1 * L_l_1));
vel_2 = vel_b + cross(omega_b,N_L_b) + cross(omega_1,(R_N1 * L_l_1)) + 0.5 * cross(omega_2,(R_N2 * L_l_2));
vel_3 = vel_b + cross(omega_b,N_L_b) + cross(omega_1,(R_N1 * L_l_1)) + cross(omega_2,(R_N2 * L_l_2)) +  0.5 * cross(omega_3,(R_N3 * L_l_3));


%% Calculate Kinetic energy
KE = 0.5 * (m_b * (vel_b.' * vel_b) + m_1 * (vel_1.' * vel_1) + ...
    + m_2 * (vel_2.' * vel_2) + m_3 * (vel_3.' * vel_3) +...
    (omega_b.' * N_I_b * omega_b) + (omega_1.' * N_I_1 * omega_1)+...
    (omega_2.' * N_I_2 * omega_2)+ (omega_3.' * N_I_3 * omega_3));

% Linar momentum
P = m_b * vel_b + m_1 * vel_1 + m_2 * vel_2 + m_3 * vel_3;

%Angular momentum
M = N_I_b * omega_b + cross(N_r_b,(m_b * vel_b)) + N_I_1 * omega_1 + cross(N_r_1,(m_1 * vel_1)) +...
    + N_I_2 * omega_2 + cross(N_r_2,(m_2 * vel_2))+ N_I_3 * omega_3 + cross(N_r_3,(m_3 * vel_3));
% Compute accelerations
ddPhi = H \ (tau - C_dPhi); 
dPhidt = [dPhi; ddPhi];

disp(t);
end